以下是一个适用于 Windows 平台的使用 OpenSSL 库的 TLS 客户端实现示例。因为 Windows 平台上的套接字 API 与 Linux 有所不同，所以代码有一些微小的区别。

在编译和运行此代码之前，请确保您已经在 Windows 上安装了适当的 openssl 库，并使用相应的头文件和库文件。

```c
#pragma comment(lib, "ws2_32.lib")
#pragma comment(lib, "libssl.lib")
#pragma comment(lib, "libcrypto.lib")

#include <stdio.h>
#include <string.h>
#include <openssl/ssl.h>
#include <openssl/err.h>
#include <winsock2.h>

#define HOST "www.example.com"
#define PORT 443
#define BUFFER_SIZE 4096
#define HTTP_GET_REQUEST "GET / HTTP/1.1\r\nHost: " HOST "\r\nConnection: close\r\n\r\n"

int main(int argc, char *argv[]) {
  // 初始化 Winsock
  WSADATA wsaData;
  if (WSAStartup(MAKEWORD(2, 0), &wsaData) != 0) {
    printf("WSAStartup failed\n");
    return 1;
  }

  // 初始化 OpenSSL
  OPENSSL_init_ssl(OPENSSL_INIT_LOAD_SSL_STRINGS | OPENSSL_INIT_LOAD_CRYPTO_STRINGS, NULL);

  // 创建新的 SSL_CTX 实例
  SSL_CTX *ssl_ctx = SSL_CTX_new(TLS_client_method());
  if (!ssl_ctx) {
    fprintf(stderr, "Error SSL_CTX creation\n");
    return 1;
  }

  // 创建新的 SSL 实例
  SSL *ssl = SSL_new(ssl_ctx);
  if (!ssl) {
    fprintf(stderr, "Error SSL creation\n");
    SSL_CTX_free(ssl_ctx);
    return 1;
  }

  // 创建套接字并连接到服务器
  SOCKET sockfd = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);
  if (sockfd == INVALID_SOCKET) {
    perror("Error socket creation");
    return 1;
  }

  // Configure server_addr structure
  struct sockaddr_in server_addr;
  memset(&server_addr, 0, sizeof(server_addr));
  server_addr.sin_family = AF_INET;
  server_addr.sin_port = htons(PORT);
  server_addr.sin_addr.S_un.S_addr = inet_addr(HOST);

  // Connect to server
  if (connect(sockfd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
    perror("Error connecting to server");
    return 1;
  }

  // Set socket
  SSL_set_fd(ssl, (int)sockfd);

  // SSL/TLS handshake
  if (SSL_connect(ssl) < 1) {
    fprintf(stderr, "Error SSL_connect\n");
    return 1;
  }

  // Send HTTP GET request
  if (SSL_write(ssl, HTTP_GET_REQUEST, strlen(HTTP_GET_REQUEST)) < 0) {
    fprintf(stderr, "Error SSL_write\n");
    return 1;
  }

  // Read server response
  char buffer[BUFFER_SIZE];
  int bytes_read = 0;
  while ((bytes_read = SSL_read(ssl, buffer, BUFFER_SIZE - 1)) > 0) {
    buffer[bytes_read] = '\0';
    printf("%s", buffer);
  }

  // Cleanup
  SSL_shutdown(ssl);
  closesocket(sockfd);
  SSL_free(ssl);
  SSL_CTX_free(ssl_ctx);
  WSACleanup();

  return 0;
}
```

